import React from 'react';
import { Link, Outlet, useLocation } from 'react-router-dom';
import { useAuth } from '../../context/AuthContext';

const TraineeDashboard = () => {
  const { user, logout } = useAuth();
  const location = useLocation();

  const navItems = [
    { path: '/dashboard', label: 'Dashboard', icon: 'M3 12l2-2m0 0l7-7 7 7M5 10v10a1 1 0 001 1h3m10-11l2 2m-2-2v10a1 1 0 01-1 1h-3m-6 0a1 1 0 001-1v-4a1 1 0 011-1h2a1 1 0 011 1v4a1 1 0 001 1m-6 0h6' },
    { path: '/trainee/courses', label: 'Mes Cours', icon: 'M2 3h6a4 4 0 0 1 4 4v14a3 3 0 0 0-3-3H2zM22 3h-6a4 4 0 0 0-4 4v14a3 3 0 0 1 3-3h7z' },
    { path: '/trainee/controls', label: 'Mes Contrôles', icon: 'M14 2H6a2 2 0 0 0-2 2v16a2 2 0 0 0 2 2h12a2 2 0 0 0 2-2V8zM14 2v6h6M16 13H8M16 17H8M10 9H8' },
    { path: '/trainee/corrections', label: 'Mes Corrections', icon: 'M9 11l3 3L22 4M21 12v7a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2V5a2 2 0 0 1 2-2h11' },
    { path: '/trainee/research', label: 'Ma Recherche', icon: 'M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z' },
  ];

  const getRoleLabel = (role) => {
    const labels = { admin: 'Administrateur', instructor: 'Instructeur', coordinator: 'Coordinateur', supervisor: 'Superviseur', trainee: 'Stagiaire' };
    return labels[role] || role;
  };

  const getPermissions = (role) => {
    const permissions = {
      admin: ['Créer et gérer tous les comptes utilisateurs', 'Gérer les matières', 'Créer des cours, contrôles et corrections', 'Voir les statistiques globales', 'Accéder à toutes les fonctionnalités'],
      instructor: ['Créer des cours pour les matières', 'Créer des contrôles et corrections', 'Publier des sujets de recherche', 'Noter les soumissions des stagiaires', 'Voir les progrès des stagiaires'],
      coordinator: ['Voir la progression des stagiaires', 'Suivre la formation globale', 'Voir les statistiques de formation'],
      supervisor: ['Voir la progression détaillée des stagiaires', 'Voir les soumissions des stagiaires', 'Suivre la formation de manière approfondie', 'Voir les statistiques détaillées'],
      trainee: ['Consulter les cours', 'Télécharger et soumettre les contrôles', 'Consulter les corrections', 'Soumettre les recherches', 'Voir sa progression']
    };
    return permissions[role] || [];
  };

  const getHowItWorks = (role) => {
    const explanations = {
      admin: { title: 'Comment gérer la plateforme', steps: ['1. Créez des comptes pour les instructeurs, coordonnateurs, superviseurs et stagiaires', '2. Créez des matières et assignez un instructeur à chaque matière', '3. Les instructeurs peuvent ensuite créer les cours, contrôles et corrections', '4. Suivez les statistiques globales de la plateforme'] },
      instructor: { title: 'Comment gérer la formation', steps: ['1. Créez des cours pour chaque partie (1-4) de votre matière', '2. Créez des contrôles pour chaque partie', '3. Publiez les contrôles pour que les stagiaires puissent les télécharger', '4. Après les dates limites, téléchargez les soumissions des stagiaires', '5. Créez les corrections après chaque contrôle', '6. Créez des sujets de recherche pour les stagiaires'] },
      coordinator: { title: 'Comment suivre la formation', steps: ['1. Consultez la progression des stagiaires par matière', '2. Visualisez les statistiques globales de formation', '3. Identifiez les stagiaires en retard', '4. Coordonnez avec les autres responsables'] },
      supervisor: { title: 'Comment superviser la formation', steps: ['1. Consultez la progression détaillée de chaque stagiaire', '2. Visualisez toutes les soumissions des contrôles', '3. Consultez les recherches soumises par les stagiaires', '4. Fournissez un suivi détaillé de la formation'] },
      trainee: { 
        title: 'Comment suivre votre formation', 
        steps: [
          '1. Téléchargez les cours de chaque partie (1-4)',
          '2. Téléchargez les contrôles et soumettez vos réponses',
          '3. Consultez les corrections après chaque contrôle',
          '4. Effectuez les recherches et soumettez vos réponses',
          '5. Suivez votre progression dans le tableau de bord'
        ] 
      }
    };
    return explanations[role] || {};
  };

  const getTrainingProcess = () => {
    return [
      { part: 'Envoi 1', content: 'Cours Partie 1 + Contrôles Partie 1' },
      { part: 'Envoi 2', content: 'Correction Partie 1 + Sujet de recherche + Cours Partie 2 + Contrôles Partie 2' },
      { part: 'Envoi 3', content: 'Correction Partie 2 + Cours Partie 3 + Contrôles Partie 3' },
      { part: 'Envoi 4', content: 'Correction Partie 3 + Cours Partie 4 + Contrôles Partie 4 + Soumission recherche' },
    ];
  };

  return (
    <div className="app-container">
      <aside className="sidebar">
        <div className="sidebar-header">
          <div className="sidebar-logo">PFE <span>Formation</span></div>
        </div>
        <nav className="sidebar-nav">
          <div className="nav-section">
            <div className="nav-section-title">Menu Principal</div>
            {navItems.map((item) => (
              <Link key={item.path} to={item.path} className={`nav-item ${location.pathname === item.path ? 'active' : ''}`}>
                <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
                  <path d={item.icon} />
                </svg>
                {item.label}
              </Link>
            ))}
          </div>
          <div className="nav-section" style={{ marginTop: '20px' }}>
            <div className="nav-section-title">Mon Profil</div>
            <div style={{ padding: '10px', color: '#9CA3AF', fontSize: '12px' }}>
              <div style={{ marginBottom: '8px' }}><strong>Rôle:</strong> {getRoleLabel(user?.role)}</div>
              <div style={{ marginBottom: '8px' }}><strong>Permissions:</strong></div>
              <ul style={{ paddingLeft: '15px', margin: '0 0 10px 0' }}>
                {getPermissions(user?.role).map((perm, idx) => (
                  <li key={idx} style={{ marginBottom: '4px' }}>• {perm}</li>
                ))}
              </ul>
              
              <div style={{ marginBottom: '8px', color: '#60A5FA' }}><strong>💡 {getHowItWorks(user?.role).title}:</strong></div>
              <div style={{ fontSize: '11px', lineHeight: '1.4', marginBottom: '15px' }}>
                {getHowItWorks(user?.role).steps?.map((step, idx) => (
                  <div key={idx} style={{ marginBottom: '6px' }}>{step}</div>
                ))}
              </div>

              <div style={{ marginBottom: '8px', color: '#FCD34D' }}><strong>📚 Processus de formation:</strong></div>
              {getTrainingProcess().map((item, idx) => (
                <div key={idx} style={{ fontSize: '10px', marginBottom: '6px', borderLeft: '2px solid #F59E0B', paddingLeft: '6px' }}>
                  <strong>{item.part}:</strong> {item.content}
                </div>
              ))}
            </div>
          </div>
        </nav>
        <div className="sidebar-footer">
          <div className="user-info">
            <div className="user-avatar">{user?.first_name?.[0]}{user?.last_name?.[0]}</div>
            <div className="user-details">
              <div className="user-name">{user?.first_name} {user?.last_name}</div>
              <div className="user-role">{getRoleLabel(user?.role)}</div>
            </div>
            <button onClick={logout} style={{ background: 'none', border: 'none', color: '#fff', cursor: 'pointer', padding: '8px' }}>
              <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" width="20" height="20">
                <path d="M9 21H5a2 2 0 0 1-2-2V5a2 2 0 0 1 2-2h4M16 17l5-5-5-5M21 12H9" />
              </svg>
            </button>
          </div>
        </div>
      </aside>
      <main className="main-content">
        <Outlet />
      </main>
    </div>
  );
};

